SourceCode.Declaration:
public class HDG_PurchReceiptHelper
{
    PurchParmUpdate                 purchParmUpdate;
    FormletterOutputContract        formletterOutputContract;
    PurchTable                      purchTable;
    Map mapPurchTable;

    private Num num;
    private TransDate transDate;
    private List gList;

}

Method.Source:
[DataMemberAttribute("Num")]
public Num parmNum(Num _num = num)
{
    num = _num;
    return num;
}

[DataMemberAttribute("TransDate")]
public TransDate parmTransDate(TransDate _transDate = transDate)
{
    transDate = _transDate;
    return transDate;
}

public List parmPurchReceiptList(List _list)
{
    gList = _list;
    return gList;
}

public FormletterOutputContract parmFormletterOutputContract(FormletterOutputContract _formletterOutputContract = formletterOutputContract)
{
    formletterOutputContract = _formletterOutputContract;
    return formletterOutputContract;
}

public boolean validate()
{
    if(!gList || gList.empty())
    {
        throw error('The purchase receipt list cannot be empty.');
    }

    if(!transDate)
    {
        throw error('The transaction date is not valid.');
    }

    if(!num)
    {
        throw error('The number of receipt is not valid.');
    }

    return true;
}

public void run()
{
    HDG_PurchReceiptContract contract;

    mapPurchTable = new Map(typeName2Type(extendedTypeStr(RecId)), Types::Record);

    ListEnumerator listEnumerator = gList.getEnumerator();

    while(listEnumerator.moveNext())
    {
        contract = listEnumerator.current();

        PurchLine purchLine = PurchLine::find(contract.parmPurchId(), contract.parmLineNumber());

        // Validate
        if(!purchLine)
        {
            throw error('Purchase order information is not valid.');
        }

        if(!mapPurchTable.exists(contract.parmPurchId()))
        {
            purchTable = PurchTable::find(contract.parmPurchId());
            mapPurchTable.insert(purchTable.RecId, purchTable);
        }

        this.registerPurchLine(contract);
    }

    // Post purchase receipt
    this.postPurchReceipt();
}

private void registerPurchLine(HDG_PurchReceiptContract _contract)
{
    PurchLine               purchLine;
    InventTrans             inventTranslocal;
    InventDim               inventDimlocal;

    purchLine = PurchLine::find(_contract.parmPurchId(), _contract.parmLineNumber());

    // Get original InventTransId, InventDim
    inventTranslocal = InventTrans::findTransId(purchLine.InventTransId, true);
    inventDimlocal   = inventTranslocal.inventDim();

    // Set InventDim to InventTrans record
    inventTranslocal.inventDimId    = _contract.parmInventDimId();

    // Create register data
    InventTransWMS_Register inventTransWMS_register;
    TmpInventTransWMS       tmpInventTransWMS;

    inventTransWMS_register         = inventTransWMS_register::newStandard(tmpInventTransWMS);

    tmpInventTransWMS.clear();
    tmpInventTransWMS.initFromInventTrans(inventTranslocal);
    tmpInventTransWMS.ItemId    = inventTranslocal.ItemId;
    tmpInventTransWMS.InventQty = _contract.parmReceiveQty();
    tmpInventTransWMS.insert();

    inventTransWMS_register.writeTmpInventTransWMS(tmpInventTransWMS,
                                                   inventTranslocal,
                                                   inventDimlocal);

    inventTransWMS_register.updateInvent(inventTranslocal);
}

private void postPurchReceipt()
{
    PurchFormLetter_PackingSlip purchFormLetter_PackingSlip;

    if (!mapPurchTable.empty())
    {
        purchFormLetter_PackingSlip = PurchFormLetter::construct(DocumentStatus::PackingSlip);
        purchFormLetter_PackingSlip.parmDataSourceRecordsPacked(mapPurchTable.pack());
        purchFormLetter_PackingSlip.initNewPurchParmUpdate();
        purchFormLetter_PackingSlip.sumBy(AccountOrder::Account);
        purchFormLetter_PackingSlip.reArrangeNow(true);
        purchFormLetter_PackingSlip.update(purchTable, num, transDate, PurchUpdate::Recorded);

        formletterOutputContract = purchFormLetter_PackingSlip.getOutputContract();
    }
}
